       t.TITLE as itemTitle, t.ADDR1 as itemAddr, t.FIRSTIMAGE as itemImage
  FROM relation r
  JOIN trip t ON r.TRIP_CONTS_ID = t.CONTS_ID
 WHERE r.USER_NO = #{userNo}
   AND r.REL_CLSF = #{relClsf}

